// frontend/src/hooks/useBluetoothSensor.js
import { useState, useEffect, useCallback } from 'react';
import WebBluetoothService from '../services/webBluetoothService';

export const useBluetoothSensor = () => {
    const [status, setStatus] = useState({ connected: false, device: null });
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);
    const [bluetoothService, setBluetoothService] = useState(null);

    const connect = useCallback(async () => {
        setLoading(true);
        setError(null);
        
        try {
            const service = new WebBluetoothService();
            const result = await service.connect();
            
            if (result.success) {
                setBluetoothService(service);
                setStatus({ connected: true, device: service.device });
                return { success: true };
            } else {
                setError(result.error);
                return { success: false, error: result.error };
            }
        } catch (err) {
            setError(err.message);
            return { success: false, error: err.message };
        } finally {
            setLoading(false);
        }
    }, []);

    const disconnect = useCallback(() => {
        if (bluetoothService) {
            bluetoothService.disconnect();
            setBluetoothService(null);
            setStatus({ connected: false, device: null });
        }
    }, [bluetoothService]);

    const scanFingerprint = useCallback(async () => {
        if (!bluetoothService || !status.connected) {
            throw new Error('Not connected to sensor');
        }
        
        setLoading(true);
        try {
            const result = await bluetoothService.scanFingerprint();
            return result;
        } catch (err) {
            setError(err.message);
            throw err;
        } finally {
            setLoading(false);
        }
    }, [bluetoothService, status.connected]);

    const enrollFingerprint = useCallback(async () => {
        if (!bluetoothService || !status.connected) {
            throw new Error('Not connected to sensor');
        }
        
        setLoading(true);
        try {
            const result = await bluetoothService.enrollFingerprint();
            return result;
        } catch (err) {
            setError(err.message);
            throw err;
        } finally {
            setLoading(false);
        }
    }, [bluetoothService, status.connected]);

    return {
        status,
        loading,
        error,
        connect,
        disconnect,
        scanFingerprint,
        enrollFingerprint,
        isBluetoothSupported: !!navigator.bluetooth
    };
};
